func TestOperation_MutateFuncAdapter_RoundTrip(t *testing.T) {
	t.Parallel()

	var op Operation = MutateFunc(func(b *Bead) error {
		b.Title = "updated title"
		b.Notes = "mutated through Operation"
		return nil
	})

	b := &Bead{Title: "original title"}

