// newTestBackend returns a Backend rooted at a fresh temp dir for the explicit
// backend name supplied by the caller. The chaos suite uses it so both JSONL
// and axon run through the same Backend interface surface rather than one path
// silently defaulting to JSONL.
//
// Both backends get a 30s lock wait to handle the high concurrency in
// LargeScale tests on slow CI machines (15 goroutines × 15 beads can push
// the default 10s timeout on loaded runners).
func newTestBackend(t *testing.T, backend string) Backend {
	t.Helper()
	switch backend {
	case BackendJSONL:
		s := newJSONLStore(t)
		s.LockWait = 30 * time.Second
		return s
	case BackendAxon:
		s := newAxonStore(t)
		if ab, ok := s.backend.(*AxonBackend); ok {
			ab.LockWait = 30 * time.Second
		}
		return s
	default:
		t.Fatalf("unsupported chaos backend %q", backend)
		return nil
	}
}

// chaosBackend names a backend constructor for the parameterized chaos suite.
// Per ddx-743bc194, every backend-agnostic chaos scenario must run against both
// the JSONL default and the axon backend so a regression in either path fails
// the same suite.
type chaosBackend struct {
	name    string
	backend string
}

func chaosBackends() []chaosBackend {
	return []chaosBackend{
		{name: "jsonl", backend: BackendJSONL},
		{name: "axon", backend: BackendAxon},
	}
}

// forEachChaosBackend runs fn once per backend as a parallel subtest. The
// subtest receives a fresh Backend, so scenarios stay isolated per backend.
func forEachChaosBackend(t *testing.T, fn func(*testing.T, Backend)) {
	t.Helper()
	for _, bf := range chaosBackends() {
		bf := bf
		t.Run(bf.name, func(t *testing.T) {
			t.Parallel()
			fn(t, newTestBackend(t, bf.backend))
		})
	}
}

