// NewPreDispatchLintHook constructs the bead-lifecycle lint hook used before
// execute-loop dispatch.
func NewPreDispatchLintHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (LintResult, error) {
	return func(ctx context.Context, beadID string) (LintResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			}
		}
		if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
		}
		if store == nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("bead reader required")}
		}

		b, err := store.Get(beadID)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("load bead %s: %w", beadID, err)}
		}

		if findings := escalation.LintExecutionHints(b); len(findings) > 0 {
			rationaleParts := make([]string, 0, len(findings))
			suggestedFixes := make([]string, 0, len(findings))
			for _, finding := range findings {
				rationaleParts = append(rationaleParts, finding.Message)
				suggestedFixes = append(suggestedFixes, finding.Message)
			}
			return LintResult{
				Score:          0,
				Rationale:      strings.Join(rationaleParts, "; "),
				SuggestedFixes: suggestedFixes,
			}, nil
		}

		prompt, err := buildPreDispatchLintPrompt(b)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
		}

		runtime := AgentRunRuntime{
			Prompt:        prompt,
			WorkDir:       projectRoot,
			PromptSource:  "bead-lifecycle-lint",
			ClearProfile:  true,
			ClearMinPower: true,
			ClearMaxPower: true,
		}
		applyLifecycleHookRouting(ctx, projectRoot, svc, runner, rcfg, &runtime, SelectCheapestProfile)
		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
		if err != nil {
			switch {
			case errors.Is(err, context.Canceled), errors.Is(err, context.DeadlineExceeded):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			case isUnknownHarnessError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingHarness, Err: err}
			case isMissingSkillError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
			default:
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
			}
		}

		payload, parseErr := lintResultPayload(result)
		if parseErr != nil {
			return LintResult{}, parseErr
		}
		var out LintResult
		if err := json.Unmarshal([]byte(payload), &out); err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindBadJSON, Err: err}
		}
		return out, nil
	}
}

func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
	env := lintPromptBead{
		ID:          b.ID,
		Title:       strings.TrimSpace(b.Title),
		Type:        b.IssueType,
		Labels:      append([]string(nil), b.Labels...),
		Parent:      strings.TrimSpace(b.Parent),
		Deps:        append([]string(nil), b.DepIDs()...),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
		Notes:       strings.TrimSpace(b.Notes),
	}
	if len(b.Extra) > 0 {
		env.Custom = lintPromptCustomFields(b.Extra)
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: lint\n")
	sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
	sb.WriteString("LintResult.rationale is a single string summary; suggested_fixes and waivers_applied are flat string lists.\n")
	sb.WriteString("Return only JSON with these top-level fields.\n")
	sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
	sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func lintResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		if strings.TrimSpace(result.Error) != "" {
			return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: errors.New(strings.TrimSpace(result.Error))}
		}
		if result.ExitCode != 0 {
			return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("exit code %d with empty output", result.ExitCode)}
		}
		return "", ErrLintHookEmptyOutput
	}
	candidate, ok := extractJSONCandidate(text)
	if !ok {
		return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
	}
	return candidate, nil
}

// HasBeadLabelPrefix reports whether any label starts with the provided prefix.
func HasBeadLabelPrefix(labels []string, prefix string) bool {
	for _, l := range labels {
		if strings.HasPrefix(l, prefix) {
			return true
		}
	}
	return false
}

// BeadReader can fetch a bead by ID. Implemented by *bead.Store.
type BeadReader interface {
	Get(id string) (*bead.Bead, error)
}

// BeadEventReader reads the event history recorded against a bead.
// Implemented by *bead.Store. Used by DefaultBeadReviewer to count prior
// review escalation triggers for the same result_rev.
type BeadEventReader interface {
	Events(id string) ([]bead.BeadEvent, error)
}

// BeadReviewer runs a post-merge review for a completed bead.
type BeadReviewer interface {
	ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error)
}

// reviewGroupReviewer is the optional pre-close gate used by execute-loop.
// DefaultBeadReviewer implements it; test doubles can opt in when they need
// to exercise the unanimous-two-slot path explicitly.
type reviewGroupReviewer interface {
	ReviewGroup(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error)
}

// beadReviewInstructions is the review contract embedded in the prompt.
// The reviewing agent must produce a single JSON object matching the
// ReviewVerdict schema (schema_version: 1). The markdown contract this
// replaces silently mis-parsed `### Verdict: APPROVE` outputs whenever the
// model echoed the prompt's options header — see review_verdict.go.
const beadReviewInstructions = `You are reviewing a bead implementation against its acceptance criteria.

## AC-Check Ratification

When an <ac-check> section is present, ratify the mechanical results rather
than re-verifying them independently from the diff:

- result="pass": confirm the evidence is credible. Override to fail only if
  the evidence is fabricated — include judgment_override_reason and a diff
  citation (file:line) in the per_ac evidence string.
- result="fail": mechanically verified failure. Grade as fail and BLOCK unless

---LOOP STORE---
	Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error)
}

type ExecuteBeadExecutorFunc func(ctx context.Context, beadID string) (ExecuteBeadReport, error)

func (f ExecuteBeadExecutorFunc) Execute(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
	return f(ctx, beadID)
}

type ExecuteBeadLoopStore interface {
	ReadyExecution() ([]bead.Bead, error)
	Get(id string) (*bead.Bead, error)
	Create(b *bead.Bead) error
	Claim(id, assignee string) error
	Unclaim(id string) error
	TouchClaimHeartbeat(id string) error
	CloseWithEvidence(id, sessionID, commitSHA string) error
	AppendEvent(id string, event bead.BeadEvent) error
	Events(id string) ([]bead.BeadEvent, error)
	SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error
	AppendNotes(id string, notes string) error
	IncrNoChangesCount(id string) (int, error)
	// Reopen sets a closed bead back to open, appending notes to the bead's
	// Notes field and recording a reopen event. Used by review workflows that
	// intentionally transition a bead back into open state.
	Reopen(id, reason, notes string) error
	// Update mutates a bead in place. Used by the post-merge triage step to
	// add metadata hints (e.g. tier-pin) when the triage policy escalates after
	// repeated review BLOCKs.
	Update(id string, mutate func(*bead.Bead)) error
	UpdateWithLifecycleStatus(id string, status string, opts bead.LifecycleTransitionOptions, mutate func(*bead.Bead) error) error
	ParkToProposed(id string, reason bead.ParkReason, mutate func(*bead.Bead)) error
}

// readyDiagnoser is the optional interface the work loop uses to explain an
// empty execution queue. bead.Store satisfies it via ReadyExecutionBreakdown.
type readyDiagnoser interface {
	ReadyExecutionBreakdown() (bead.ReadyExecutionBreakdown, error)
}

// NoReadyWorkBreakdown explains why the execution-ready queue is empty.
// Populated on an ExecuteBeadLoopResult when NoReadyWork fires and the store
// exposes ReadyExecutionBreakdown.
